B.aS1=new A.iL("1. Veri Sorumlusu",'Avialish uygulamas\u0131 ("Uygulama") kapsam\u0131nda ki\u015fisel verileriniz, 6698 say\u0131l\u0131 Ki\u015fisel Verilerin Korunmas\u0131 Kanunu ("KVKK") uyar\u0131nca veri sorumlusu s\u0131fat\u0131yla taraf\u0131m\u0131zca i\u015flenmektedir.')
B.aS0=new A.iL("2. \u0130\u015flenen Ki\u015fisel Veriler","\u2022 E-posta adresi\n\u2022 Uygulama i\xe7i kullan\u0131m verileri (s\u0131nav sonu\xe7lar\u0131, ders ilerlemesi, rozet kazan\u0131mlar\u0131)\n\u2022 Cihaz bilgileri ve IP adresi\n\u2022 Google hesab\u0131 ile giri\u015f yap\u0131lmas\u0131 h\xe2linde Google taraf\u0131ndan payla\u015f\u0131lan profil bilgileri")
B.aRY=new A.iL("3. \u0130\u015fleme Ama\xe7lar\u0131","\u2022 \xdcyelik olu\u015fturma ve kimlik do\u011frulama\n\u2022 Ki\u015fiselle\u015ftirilmi\u015f \xf6\u011frenme deneyimi sunma\n\u2022 Uygulama performans\u0131 ve g\xfcvenli\u011finin sa\u011flanmas\u0131\n\u2022 Yasal y\xfck\xfcml\xfcl\xfcklerin yerine getirilmesi\n\u2022 Hizmet iyile\u015ftirme ve istatistiksel analiz")
B.aRW=new A.iL("4. Hukuki Dayanak",'Ki\u015fisel verileriniz; KVKK\'n\u0131n 5. maddesi kapsam\u0131nda "s\xf6zle\u015fmenin kurulmas\u0131 ve ifas\u0131", "me\u015fru menfaat" ve "a\xe7\u0131k r\u0131za" hukuki sebeplerine dayan\u0131larak i\u015flenmektedir.')
B.aRV=new A.iL("5. \xdc\xe7\xfcnc\xfc Ki\u015filerle Payla\u015f\u0131m","Ki\u015fisel verileriniz; hizmet altyap\u0131m\u0131z\u0131 sa\u011flayan Supabase (bulut veritaban\u0131) ve Google (kimlik do\u011frulama, reklam) gibi i\u015f ortaklar\u0131m\u0131zla, yasal zorunluluk durumlar\u0131nda ise yetkili kamu kurum ve kurulu\u015flar\u0131yla payla\u015f\u0131labilir. Bu aktar\u0131mlar KVKK'n\u0131n 8. ve 9. maddeleri \xe7er\xe7evesinde ger\xe7ekle\u015ftirilir.")
B.aRZ=new A.iL("6. Saklama S\xfcresi","Verileriniz, \xfcyeli\u011finizin devam etti\u011fi s\xfcre boyunca ve \xfcyelik sona erdikten sonra yasal y\xfck\xfcml\xfcl\xfckler kapsam\u0131nda en fazla 3 y\u0131l s\xfcreyle saklan\u0131r.")
B.aS_=new A.iL("7. Haklar\u0131n\u0131z (KVKK Md. 11)","KVKK'n\u0131n 11. maddesi kapsam\u0131nda a\u015fa\u011f\u0131daki haklara sahipsiniz:\n\u2022 Ki\u015fisel verilerinizin i\u015flenip i\u015flenmedi\u011fini \xf6\u011frenme\n\u2022 \u0130\u015flenmi\u015fse buna ili\u015fkin bilgi talep etme\n\u2022 \u0130\u015flenme amac\u0131n\u0131 ve amac\u0131na uygun kullan\u0131l\u0131p kullan\u0131lmad\u0131\u011f\u0131n\u0131 \xf6\u011frenme\n\u2022 Eksik veya yanl\u0131\u015f i\u015flenmi\u015fse d\xfczeltilmesini isteme\n\u2022 Verilerinizin silinmesini talep etme\n\u2022 \u0130\u015flemeye itiraz etme")
B.aRX=new A.iL("8. \u0130leti\u015fim","Haklar\u0131n\u0131z\u0131 kullanmak veya sorular\u0131n\u0131z i\xe7in: destek@avialish.com adresine e-posta g\xf6nderebilirsiniz.")
