B.a1s=new A.m(B.z,"G\xfcvenlik ekipman\u0131 adlar\u0131 kesin olmal\u0131d\u0131r","G\xfcvenlik ekipman\u0131 i\xe7in yanl\u0131\u015f isimler kullanmak tehlikeli yanl\u0131\u015f anla\u015f\u0131lmalara yol a\xe7abilir. S\u0131nav sorular\u0131 ekipman adlar\u0131, i\u015flevleri ve bunlarla kullan\u0131lan fiiller hakk\u0131nda kesin bilgi \xf6l\xe7er.\n\nBu ders, t\xfcm havac\u0131l\u0131k rolleri i\xe7in en s\u0131k s\u0131nanan g\xfcvenlik ekipman\u0131 terimlerini kapsar.",null,null,null,null,null,null,null)
B.a5h=new A.m(B.w,"\ud83d\udee1\ufe0f Kabin G\xfcvenlik Ekipmanlar\u0131","**Portable oxygen unit** \u2014 portable O\u2082 bottle for crew use\n**Drop-down oxygen mask** \u2014 passenger masks, auto-deploys above 10,000 ft cabin alt\n**Life vest / Life jacket** \u2014 under-seat flotation device\n**Emergency exit** \u2014 floor-level lighting marks the path\n**Escape slide** \u2014 inflatable slide for rapid evacuation\n**Fire extinguisher** \u2014 Halon type in cockpit, water/CO\u2082 in cabin\n**ELT** \u2014 Emergency Locator Transmitter (activates on impact)",null,null,null,null,null,null,null)
