B.a1Y=new A.m(B.z,"ATC talimatlar\u0131n\u0131n yap\u0131s\u0131",'ATC (Air Traffic Control) talimatlar\u0131 k\u0131sa, net ve standart fiillerle verilir. Pilotlar bu talimatlar\u0131 tam olarak "readback" (geri okuma) yapmal\u0131d\u0131r. Yanl\u0131\u015f anlama veya eksik readback, u\xe7u\u015f emniyetini do\u011frudan tehdit eder.',null,null,null,null,null,null,null)
