B.a04=new A.m(B.z,"Yer hareketi neden kritiktir?","Havaliman\u0131 yer hareketi, u\xe7u\u015f emniyeti a\xe7\u0131s\u0131ndan en riskli fazlardan biridir. Pist ihlalleri (runway incursions) d\xfcnya genelinde ciddi kazalara neden olmaktad\u0131r. Bu nedenle yer hareketiyle ilgili talimatlar\u0131n tam olarak anla\u015f\u0131lmas\u0131 hayati \xf6nem ta\u015f\u0131r.",null,null,null,null,null,null,null)
