B.a3_=new A.m(B.z,"Acil durum dili tam olarak \xf6\u011frenilmelidir","Ger\xe7ek acil durumlarda ve s\u0131nav sorular\u0131nda do\u011fru kelimeyi kullanmak kritik fark yaratabilir. ICAO standartlar\u0131 acil durumlar i\xe7in belirli terimler tan\u0131mlar \u2014 bunlar farkl\u0131 ifadeyle anlat\u0131lamaz.\n\nBu ders, acil durumla ilgili s\u0131nav sorular\u0131nda en s\u0131k kar\u015f\u0131la\u015f\u0131lan kelime bilgisine odaklan\u0131r.",null,null,null,null,null,null,null)
B.a00=new A.m(B.w,"\ud83d\udea8 Acil Durum S\u0131n\u0131fland\u0131rmas\u0131","**Distress** \u2014 state of being threatened by serious and/or imminent danger, requiring immediate assistance (MAYDAY)\n\n**Urgency** \u2014 condition concerning the safety of an aircraft or other vehicle, or of some person on board or in sight, but not requiring immediate assistance (PAN-PAN)\n\n**Emergency** \u2014 broad term covering both distress and urgency situations\n\n**Incident** \u2014 occurrence other than an accident associated with flight operation\n**Accident** \u2014 occurrence resulting in death, injury, or substantial aircraft damage",null,null,null,null,null,null,null)
