B.a4T=new A.m(B.aw,"\u2708\ufe0f S\u0131nav \u0130pucu",'Temel aktarma fiilleri ve edatlar\u0131:\n\u2022 said (that) \u2014 genel ifade\n\u2022 told + ki\u015fi + (that) \u2014 "ona s\xf6yledi"\n\u2022 reported (that) \u2014 resmi/yaz\u0131l\u0131 rapor\n\u2022 informed + ki\u015fi + (that) \u2014 resmi bildirim\n\u2022 warned + ki\u015fi + (that/about) \u2014 tehlike uyard\u0131\n\n"said" sonras\u0131nda edat gelmez: \u2713 "said **that**" / \u2717 "said **to** him that"',null,null,null,null,null,null,null)
