B.T1=new A.a1('"Unless the hydraulic pressure is restored, gear extension will be performed manually."',"Hidrolik bas\u0131n\xe7 geri gelmezse, ini\u015f tak\u0131m\u0131 manuel olarak indirilecek.","Unless \u2026 is restored \u2026 will be performed")
B.UL=new A.a1('"The landing may be continued provided that the reported RVR is not less than 550 metres."',"Bildirilen RVR 550 metreden az olmad\u0131\u011f\u0131 s\xfcrece ini\u015f s\xfcrd\xfcr\xfclebilir.","provided that \u2026 is not less than")
