B.a3n=new A.m(B.z,"TAF nedir?","**TAF** (Terminal Aerodrome Forecast), bir havaliman\u0131 i\xe7in 24 veya 30 saatlik hava tahminidir. METAR anl\u0131k durumu verirken TAF gelecekteki beklenen ko\u015fullar\u0131 belirtir. U\xe7u\u015f planlama a\xe7\u0131s\u0131ndan kritik \xf6neme sahiptir.",null,null,null,null,null,null,null)
B.a0s=new A.m(B.w,"TAF Format\u0131","**\xd6rnek TAF:**\nTAF LTBA 120500Z 1206/1312\n9999 FEW020 SCT060\nBECMG 1208/1210 BKN015 -RA\nTEMPO 1214/1218 4000 TSRA BKN010CB\n\n**A\xe7\u0131klama:**\n\u2022 LTBA \u2014 \u0130stanbul (havaliman\u0131 ICAO kodu)\n\u2022 120500Z \u2014 12. g\xfcn\xfc 05:00 UTC'de yay\u0131nland\u0131\n\u2022 1206/1312 \u2014 Ge\xe7erlilik: 12. g\xfcn 06:00 \u2013 13. g\xfcn 12:00 UTC\n\u2022 9999 \u2014 10 km veya \xfczeri g\xf6r\xfc\u015f\n\u2022 BECMG \u2014 Gradually becoming (kademeli de\u011fi\u015fim)\n\u2022 TEMPO \u2014 Temporary fluctuation (ge\xe7ici, < 1 saat)\n\u2022 TSRA \u2014 Thunderstorm with rain (g\xf6k g\xfcr\xfclt\xfcl\xfc sa\u011fanak)\n\u2022 CB \u2014 Cumulonimbus",null,null,null,null,null,null,null)
