B.a2S=new A.m(B.z,"D\xfc\u015f\xfck g\xf6r\xfc\u015f operasyonlar\u0131 kesin dil gerektirir","CAT II ve CAT III yakla\u015fmalar\u0131 otomatik indi\u015f sistemleri kullan\u0131larak \xe7ok d\xfc\u015f\xfck g\xf6r\xfc\u015f ko\u015fullar\u0131nda ger\xe7ekle\u015ftirilir. Bu prosed\xfcrlerdeki ifadeler, uyar\u0131lar ve s\xf6zl\xfc bildirimler havac\u0131l\u0131k \u0130ngilizcesinin en kesin tan\u0131ml\u0131 ifadeleri aras\u0131ndad\u0131r.\n\nBu alandaki c\xfcmle tamamlama sorular\u0131, prosed\xfcr terminolojisinin tam bilgisini gerektirir.",null,null,null,null,null,null,null)
B.a_F=new A.m(B.w,"\ud83c\udf2b\ufe0f ILS Kategorileri","**CAT I** \u2014 DH \u2265200ft, RVR \u2265550m (standard ILS)\n**CAT II** \u2014 DH 100\u2013200ft, RVR \u2265300m (needs specific aircraft/crew cert)\n**CAT IIIA** \u2014 DH <100ft OR no DH, RVR \u2265200m\n**CAT IIIB** \u2014 DH <50ft OR no DH, RVR 50\u2013200m\n**CAT IIIC** \u2014 No DH, No RVR limit (still not in service)\n\n**LVP** \u2014 Low Visibility Procedures (activated by airport when RVR <600m)\n**LVT** \u2014 Low Visibility Takeoff",null,null,null,null,null,null,null)
B.a4U=new A.m(B.w,"\ud83d\udce2 CAT III S\xf6zl\xfc Bildirimleri",'Standart CAT III yakla\u015fma s\xf6zl\xfc bildirimleri (s\u0131rayla):\n1. "**Localizer alive**" \u2014 ILS localizer yakaland\u0131\n2. "**Glide slope alive**" \u2014 dikey rehberlik yakaland\u0131\n3. "**Land 3**" \u2014 otomatik indi\u015f modu onayland\u0131 (A320 ailesi)\n4. "**1,000 feet**" \u2014 standart kontrol irtifas\u0131\n5. "**500 feet**" \u2014 istikrar kontrol\xfc\n6. "**100 feet**" \u2014 g\xf6rsel veya etrafta d\xf6n\xfc\u015f karar\u0131\n7. "**50, 40, 30, 20, 10**" \u2014 radyo altimetre \xe7a\u011fr\u0131lar\u0131\n8. "**Touchdown**" \u2192 "**Decelerate**" \u2192 "**Vacate**"',null,null,null,null,null,null,null)
B.TQ=new A.a1("During LVP, ground movement must be strictly controlled to prevent runway incursion.","LVP s\u0131ras\u0131nda pist ihlalini \xf6nlemek i\xe7in yer hareketi kesinlikle kontrol edilmelidir.","LVP")
B.Tf=new A.a1("At Decision Height, if the required visual reference is not established, a go-around must be executed.","Karar \u0130rtifas\u0131nda, gerekli g\xf6rsel referans sa\u011flanamazsa t\u0131rman\u0131\u015f prosed\xfcr\xfc uygulanmal\u0131d\u0131r.","Decision Height")
