B.a3k=new A.m(B.z,"Turb\xfclansta Kabin Y\xf6netimi","Turb\xfclans an\u0131nda kabin g\xf6revlisi **hem yolcular\u0131 sakinle\u015ftirmeli** hem de **g\xfcvenlik talimatlar\u0131n\u0131 net bi\xe7imde iletmelidir**. \u0130leti\u015fim tonu:\n\n\u2022 **Sakin ama otoriter** \u2014 panik yaratmadan net talimat\n\u2022 **Basit ve anla\u015f\u0131l\u0131r \u0130ngilizce** \u2014 yolcunun anlayaca\u011f\u0131 kelimeler\n\u2022 **Empatik** \u2014 yolcunun korkusunu onaylamak",null,null,null,null,null,null,null)
B.Qr=new A.bS(B.dE,"Cabin crew, be seated immediately.","Kabin ekibi, hemen oturun.",!0)
B.Qp=new A.bS(B.dD,"Ladies and gentlemen, the captain has switched on the fasten seatbelt sign. Please return to your seats and fasten your seatbelts immediately.","Bayanlar ve baylar, kaptan emniyet kemeri i\u015faretini yakt\u0131. L\xfctfen hemen yerinize d\xf6n\xfcn ve emniyet kemerinizi ba\u011flay\u0131n.",!0)
B.ob=new A.pk(3,"passenger")
B.Qy=new A.bS(B.ob,"Excuse me, is this dangerous? I'm very scared.","Affedersiniz, bu tehlikeli mi? \xc7ok korkuyorum.",!1)
B.Qu=new A.bS(B.dD,"I completely understand your concern. This is moderate turbulence \u2014 it is uncomfortable but completely safe. The aircraft is designed for this. Please keep your seatbelt fastened.","Endi\u015fenizi \xe7ok iyi anl\u0131yorum. Bu orta \u015fiddette turb\xfclans \u2014 rahats\u0131z edici ama tamamen g\xfcvenli. U\xe7ak bunun i\xe7in tasarlanm\u0131\u015f. L\xfctfen emniyet kemerinizi ba\u011fl\u0131 tutun.",!0)
B.QJ=new A.bS(B.ob,"Can I go to the lavatory?","Tuvalete gidebilir miyim?",!1)
B.QH=new A.bS(B.dD,"I'm sorry, that is not possible right now for your safety. Please remain seated with your seatbelt fastened until the sign is switched off.","\xdczg\xfcn\xfcm, g\xfcvenli\u011finiz i\xe7in \u015fu an bu m\xfcmk\xfcn de\u011fil. \u0130\u015faret s\xf6nd\xfcr\xfclene kadar l\xfctfen emniyet kemerinizle oturmaya devam edin.",!1)
B.QV=new A.bS(B.dD,"Ladies and gentlemen, the fasten seatbelt sign has been switched off. You may move around the cabin, but we recommend keeping your seatbelt fastened while seated.","Bayanlar ve baylar, emniyet kemeri i\u015fareti s\xf6nd\xfcr\xfcld\xfc. Kabinde dola\u015fabilirsiniz, ancak oturdu\u011funuzda emniyet kemerinizi ba\u011fl\u0131 tutman\u0131z\u0131 \xf6neririz.",!1)
B.ahF=s([B.Qr,B.Qp,B.Qy,B.Qu,B.QJ,B.QH,B.QV],t.B3)
B.a5Y=new A.m(B.f7,"Ciddi Turb\xfclans An\u0131nda","U\xe7u\u015f s\u0131ras\u0131nda beklenmeyen ciddi turb\xfclans",null,null,null,B.ahF,null,null,null)
B.Uy=new A.a1("Please fasten your seatbelt immediately.","L\xfctfen emniyet kemerinizi hemen ba\u011flay\u0131n.","fasten your seatbelt")
B.U5=new A.a1("This is [light/moderate/severe] turbulence.","Bu [hafif/orta/\u015fiddetli] turb\xfclanst\u0131r.","turbulence")
B.VQ=new A.a1("The aircraft is designed for this condition.","U\xe7ak bu durum i\xe7in tasarlanm\u0131\u015ft\u0131r.","designed for")
