B.a30=new A.m(B.z,"Havada T\u0131bbi Acil Durumlar",'Havada t\u0131bbi acil durumda kabin g\xf6revlisi \xfc\xe7 ad\u0131m\u0131 h\u0131zla uygular:\n\n1. **\u0130lk de\u011ferlendirme** \u2014 bilinci, solunumu, nabz\u0131 kontrol et\n2. **Kaptan bildirim** \u2014 belirlenen formatta bildir\n3. **Doktor \xe7a\u011fr\u0131s\u0131** \u2014 "Is there a doctor on board?"\n\nKaptan, gerekirse **divert** (rota de\u011fi\u015fikli\u011fi) karar\u0131 verir.',null,null,null,null,null,null,null)
B.QD=new A.bS(B.dD,"Captain, this is the senior cabin crew. We have a medical situation in the cabin. Passenger in seat 24A is unconscious, unresponsive. CPR may be required.","Kaptan, ben ba\u015f kabin g\xf6revlisiyim. Kabinde t\u0131bbi bir durum var. 24A koltu\u011fundaki yolcu bilin\xe7siz, yan\u0131t vermiyor. CPR gerekebilir.",!0)
B.QN=new A.bS(B.dE,"Understood. Is there a medical professional on board?","Anla\u015f\u0131ld\u0131. U\xe7akta t\u0131bbi personel var m\u0131?",!1)
B.Qk=new A.bS(B.dD,"We are asking now. Ladies and gentlemen, is there a doctor or medical professional on board? Please press the call button or come to seat 24A.","\u015eu an soruyoruz. Bayanlar ve baylar, u\xe7akta doktor veya t\u0131bbi personel var m\u0131? L\xfctfen \xe7a\u011fr\u0131 butonuna bas\u0131n veya 24A koltu\u011funa gelin.",!1)
B.QI=new A.bS(B.ob,"I'm a cardiologist. I can help.","Ben kardiyologum. Yard\u0131mc\u0131 olabilirim.",!1)
B.QK=new A.bS(B.dD,"Captain, we have a cardiologist assisting. Patient is breathing but unconscious. Doctor requests supplemental oxygen and medical kit.","Kaptan, bir kardiyolog yard\u0131m ediyor. Hasta nefes al\u0131yor ama bilin\xe7siz. Doktor ek oksijen ve t\u0131bbi kit talep ediyor.",!0)
B.Qg=new A.bS(B.dE,"Roger. I am contacting medical ground support. Prepare for possible diversion. Keep me updated every 5 minutes.","Anla\u015f\u0131ld\u0131. Medikal yer deste\u011fiyle ileti\u015fime ge\xe7iyorum. Olas\u0131 rota de\u011fi\u015fikli\u011fine haz\u0131rlan\u0131n. Her 5 dakikada g\xfcncelleyin.",!0)
B.QR=new A.bS(B.dD,"Understood. Captain, doctor advises diversion is necessary. Patient condition is deteriorating.","Anla\u015f\u0131ld\u0131. Kaptan, doktor rota de\u011fi\u015fikli\u011finin gerekli oldu\u011funu s\xf6yl\xfcyor. Hastan\u0131n durumu k\xf6t\xfcle\u015fiyor.",!1)
B.Qm=new A.bS(B.dE,"Cabin crew, we are diverting to Ankara. ETA 25 minutes. Medical team will be at the gate.","Kabin ekibi, Ankara'ya sap\u0131yoruz. Tahmini var\u0131\u015f 25 dakika. T\u0131bbi ekip kap\u0131da bekliyor olacak.",!1)
