B.a2p=new A.m(B.z,"Hizmet dili neden \xf6zel bir beceridir","Kabin g\xf6revlileri hem **hizmet veren** hem de **otorite temsilcisi** rol\xfcndedir. Bu nedenle yolcularla kurulan ileti\u015fimde hem nazik hem de net olmak gerekir.\n\nFarkl\u0131 durumlara g\xf6re farkl\u0131 dil d\xfczeyleri kullan\u0131l\u0131r: normal hizmet i\xe7in yumu\u015fak istekler, g\xfcvenlik kurallar\u0131 i\xe7in daha do\u011frudan ifadeler.",null,null,null,null,null,null,null)
B.a1c=new A.m(B.w,"\ud83d\udcac \u0130stek ve Y\xf6nerge Kal\u0131plar\u0131",'**Nazik istekler (hizmet):**\n\u2022 "Would you like \u2026?" \u2014 teklif\n\u2022 "Could I get you \u2026?" \u2014 teklif\n\u2022 "Would you mind \u2026?" \u2014 rica\n\u2022 "I\'m afraid \u2026" \u2014 olumsuz yan\u0131t verme\n\n**Do\u011frudan y\xf6nergeler (g\xfcvenlik):**\n\u2022 "Please return to your seat."\n\u2022 "I need you to fasten your seatbelt now."\n\u2022 "Sir/Ma\'am, this item must be stowed."\n\n**\u015eikayet y\xf6netimi:**\n\u2022 "I understand your concern, and I apologize for the inconvenience."\n\u2022 "I\'ll do my best to \u2026"\n\u2022 "Allow me to \u2026"',null,null,null,null,null,null,null)
