B.a1d=new A.m(B.z,"Acil durumda dil kesinli\u011fi hayat kurtar\u0131r",'Acil durum komutlar\u0131 **k\u0131sa, net ve teredd\xfcts\xfcz** olmal\u0131d\u0131r. Normal hizmet dilinin aksine, acil durumlarda "please" veya "would you mind" kullan\u0131lmaz \u2014 do\u011frudan emir kipi tercih edilir.\n\nEACCS (Emergency Aircraft Crew Communication System) standartlar\u0131na g\xf6re acil durum anonslar\u0131 uluslararas\u0131 standart ifadeler i\xe7erir.',null,null,null,null,null,null,null)
B.a1u=new A.m(B.w,"\u26a0\ufe0f Standart Acil Durum Komutlar\u0131",'**Brace komutu:**\n\u2022 "Brace! Brace! Brace!" \u2014 acil ini\u015f pozisyonu\n\u2022 "Head down! Stay down!"\n\n**Tahliye komutlar\u0131:**\n\u2022 "Release seatbelts! Come this way!"\n\u2022 "Leave everything! Get out!"\n\u2022 "Jump and slide!" (kayd\u0131raklarda)\n\n**Yang\u0131n/duman:**\n\u2022 "There is smoke in the cabin. Please remain calm and follow crew instructions."\n\n**T\u0131bbi:**\n\u2022 "Is there a doctor or medical professional on board?"\n\n**Kap\u0131 g\xfcvenli\u011fi:**\n\u2022 "Doors to manual and cross-check" / "Doors to automatic and cross-check"',null,null,null,null,null,null,null)
