B.a18=new A.m(B.z,"Tehlikeli madde fark\u0131ndal\u0131\u011f\u0131 neden zorunludur","ICAO Technical Instructions ve IATA DGR (Dangerous Goods Regulations) uyar\u0131nca kabin ekibi tehlikeli madde tan\u0131mlama ve bildirme konusunda e\u011fitim almal\u0131d\u0131r.\n\nTehlikeli maddeler u\xe7ak g\xfcvenli\u011fine ciddi tehdit olu\u015fturabilir. Do\u011fru tan\u0131mlama ve h\u0131zl\u0131 bildirim \xe7ok \xf6nemlidir.",null,null,null,null,null,null,null)
B.a2X=new A.m(B.w,"\ud83c\udff7\ufe0f IATA DG Kategorileri",'**9 Ana Tehlike S\u0131n\u0131f\u0131:**\n\u2022 Class 1: Explosives \u2014 Patlay\u0131c\u0131lar\n\u2022 Class 2: Gases \u2014 Gazlar\n\u2022 Class 3: Flammable liquids \u2014 Yan\u0131c\u0131 s\u0131v\u0131lar\n\u2022 Class 4: Flammable solids \u2014 Yan\u0131c\u0131 kat\u0131lar\n\u2022 Class 5: Oxidizing substances \u2014 Oksitleyici maddeler\n\u2022 Class 6: Toxic substances \u2014 Toksik maddeler\n\u2022 Class 7: Radioactive material \u2014 Radyoaktif materyal\n\u2022 Class 8: Corrosives \u2014 A\u015f\u0131nd\u0131r\u0131c\u0131lar\n\u2022 Class 9: Miscellaneous \u2014 \xc7e\u015fitli tehlikeli maddeler (lityum piller dahil)\n\n**Yasakl\u0131 kalemler bildirimi:**\n\u2022 "This item is a prohibited article under IATA regulations."\n\u2022 "This item cannot be carried on board."',null,null,null,null,null,null,null)
