B.a1M=new A.m(B.z,"G\xfcvenlik demonstrasyonu","ICAO ve havayolu SOPlar\u0131 gere\u011fi t\xfcm yolculara u\xe7u\u015f \xf6ncesinde g\xfcvenlik demonstrasyonu yap\u0131lmal\u0131 veya video g\xf6sterilmelidir. Kullan\u0131lan dil standartla\u015ft\u0131r\u0131lm\u0131\u015ft\u0131r.",null,null,null,null,null,null,null)
