B.a4Q=new A.m(B.z,"Airworthiness Directive (AD) nedir","Airworthiness Directives (ADs), havac\u0131l\u0131k otoriteleri (EASA, FAA, SHGM) taraf\u0131ndan yay\u0131mlanan **zorunlu bak\u0131m direktifleridir**. Belirli bir g\xfcvenlik sorunu tespit edildi\u011finde yay\u0131mlan\u0131r ve uyum **yasal zorunluluktur**.\n\nBir AD'yi okuyamayan veya yanl\u0131\u015f yorumlayan bir teknisyen hem u\xe7a\u011f\u0131 hem de kariyerini tehlikeye atar.",null,null,null,null,null,null,null)
B.a4P=new A.m(B.w,"\ud83d\udccb AD Yap\u0131s\u0131 ve Anahtar \u0130fadeler",'**Tipik AD b\xf6l\xfcmleri:**\n\u2022 Applicability \u2014 hangi u\xe7ak/motor tiplerine uygulan\u0131r\n\u2022 Reason \u2014 direktifin nedeni\n\u2022 Description of action \u2014 yap\u0131lacak i\u015flem\n\u2022 Compliance \u2014 uyum s\xfcresi ve ko\u015fullar\u0131\n\u2022 Alternative Methods of Compliance (AMOC) \u2014 alternatif uyum y\xf6ntemi\n\n**Uyumluluk ifadeleri:**\n\u2022 "This AD requires \u2026" \u2014 zorunlu eylem\n\u2022 "Within [X] flight hours after the effective date" \u2014 uyum s\xfcresi\n\u2022 "Before further flight" \u2014 acil, bir sonraki u\xe7u\u015ftan \xf6nce\n\u2022 "At each [check type] interval" \u2014 periyodik\n\u2022 "Unless already accomplished" \u2014 daha \xf6nce yap\u0131lm\u0131\u015fsa ge\xe7erli',null,null,null,null,null,null,null)
