B.a3I=new A.m(B.z,"Teknik g\xfcnl\xfck nedir?","**Aircraft Technical Log (ATL)**, u\xe7akla birlikte seyahat eden ve her u\xe7u\u015f segmentinde doldurulmas\u0131 zorunlu olan belgedir. Ar\u0131zalar\u0131, yap\u0131lan i\u015flemleri ve u\xe7u\u015fa elveri\u015flilik beyan\u0131n\u0131 i\xe7erir.",null,null,null,null,null,null,null)
B.a2x=new A.m(B.w,"ATL Giri\u015fi \u0130fadeleri",'**Ar\u0131za kayd\u0131 (Defect entry):**\n"Captain\'s report: [defect description]. Aircraft serviceable for next flight with defect deferred to MEL item [X]."\n\n**Giderme kayd\u0131 (Rectification):**\n"Rectified in accordance with AMM Chapter [X], Task [X]. Part replaced: P/N [X], S/N [X]. Aircraft certified serviceable."\n\n**Erteleme (Deferral):**\n"Defect deferred under MEL item [X] for [X] calendar days. Placard installed."\n\n**Teknisyen imzas\u0131:**\n"I certify that the work specified above has been carried out in accordance with Part-145 and the data specified therein."',null,null,null,null,null,null,null)
