B.a_i=new A.m(B.z,"NDT nedir?","**NDT** (Non-Destructive Testing / Tahribats\u0131z Muayene), par\xe7ay\u0131 bozmadan veya de\u011fi\u015ftirmeden i\xe7 ve y\xfczey kusurlar\u0131n\u0131 tespit etmek i\xe7in kullan\u0131lan muayene y\xf6ntemlerinin genel ad\u0131d\u0131r.",null,null,null,null,null,null,null)
B.a0p=new A.m(B.w,"NDT Y\xf6ntemleri",'**VT** \u2014 Visual Testing: do\u011frudan veya dolayl\u0131 g\xf6rsel muayene\n**PT** \u2014 Penetrant Testing: y\xfczey \xe7atlaklar\u0131nda floresan boya kullan\u0131m\u0131\n**MT** \u2014 Magnetic Particle Testing: manyetik malzemelerde y\xfczey ve y\xfczey alt\u0131 kusurlar\u0131\n**UT** \u2014 Ultrasonic Testing: ses dalgalar\u0131 ile i\xe7 kusur tespiti; thickness measurement\n**ET** \u2014 Eddy Current Testing: elektrik iletken malzemelerde y\xfczey/y\xfczey alt\u0131\n**RT** \u2014 Radiographic Testing: X-\u0131\u015f\u0131n\u0131 veya gama \u0131\u015f\u0131n\u0131yla i\xe7 yap\u0131 g\xf6r\xfcnt\xfcleme\n**Borescope** \u2014 optik cihazla motor i\xe7 kanallar\u0131n\u0131 inceleme\n\n**Rapor ifadeleri:**\n"No cracks, corrosion, or other defects noted."\n"Indication found at [location]. Further evaluation required."\n"Part accepted / rejected in accordance with engineering data."',null,null,null,null,null,null,null)
B.afE=s(["non-metallic composite structures","electrically conductive materials such as aluminium","fuel system rubber seals","hydraulic fluid contamination"],t.s)
