B.qm={pilot:0,atc:1,cabin_crew:2,student:3}
B.axt=new A.U("Modal Fiiller & Ko\u015fullu Yap\u0131lar","Gramer eksiklikleri, takas onaylar\u0131n\u0131 (clearance readback) ve PIREP do\u011frulu\u011funu do\u011frudan etkiler. shall/must/should ve operasyonel ba\u011flamlarda if-c\xfcmleciklerine odaklan.")
B.axT=new A.U("Talimatlar\u0131nda Zaman Tutarl\u0131l\u0131\u011f\u0131","Tutars\u0131z zaman kullan\u0131m\u0131, trafik bilgisinde belirsizli\u011fe yol a\xe7ar. ATC koordinasyon c\xfcmlelerinde edilgen \xe7at\u0131 ve gelecek zamana odaklan.")
B.axl=new A.U("Emir Kipi & Modal Yap\u0131lar","G\xfcvenlik anonslar\u0131 kesin emir kipi ve modal gramer gerektirir. Yolcular acil durumlarda net talimatlar almal\u0131d\u0131r.")
B.axK=new A.U("Temel Havac\u0131l\u0131k Gramer Kal\u0131plar\u0131","Modal fiiller, edilgen yap\u0131lar ve ko\u015fullu c\xfcmleler \u2014 ICAO standart havac\u0131l\u0131k \u0130ngilizcesinin \xfc\xe7 temel dire\u011fini \xf6\u011fren.")
B.amC=new A.bm(B.qm,[B.axt,B.axT,B.axl,B.axK],t.dM)
B.axD=new A.U("METAR/TAF & NOTAM Terminolojisi","Hava durumu ve NOTAM kelime bilgisi, u\xe7u\u015f \xf6ncesi planlama ve u\xe7u\u015f i\xe7i karar verme i\xe7in kritiktir. METAR k\u0131saltmalar\u0131n\u0131 \xe7\xf6zme h\u0131z\u0131n\u0131 geli\u015ftir.")
B.ayR=new A.U("SID/STAR & Holding Fraseolojisi","Kalk\u0131\u015f ve ini\u015f prosed\xfcrlerine ait kesin kelime bilgisi, yo\u011fun trafik ortamlar\u0131nda yanl\u0131\u015f anla\u015f\u0131lmalar\u0131 \xf6nler. ICAO Doc 4444 fraseolojisine odaklan.")
B.axy=new A.U("Emniyet Ekipman\u0131 Terminolojisi","Emniyet ekipman\u0131 ve prosed\xfcrlerinin do\u011fru adlar\u0131, ICAO uyumu ve yolcu g\xfcvenli\u011fi y\xf6netimi i\xe7in vazge\xe7ilmezdir.")
B.azH=new A.U("ICAO Temel Havac\u0131l\u0131k Kelime Bilgisi","ATC fraseolojisi, u\xe7ak sistemleri kelime bilgisi ve t\xfcm havac\u0131l\u0131k rollerinde kullan\u0131lan standart ICAO terminolojisiyle temelini olu\u015ftur.")
B.amB=new A.bm(B.qm,[B.axD,B.ayR,B.axy,B.azH],t.dM)
B.az9=new A.U("Operasyonel Belge Anlama","Zaman bask\u0131s\u0131 alt\u0131nda NOTAM ve OFP okumak, s\u0131navlarda yayg\u0131n ba\u015far\u0131s\u0131zl\u0131k noktas\u0131d\u0131r. Yo\u011fun havac\u0131l\u0131k metinlerinden anahtar verileri 90 saniye i\xe7inde \xe7\u0131karma prati\u011fi yap.")
B.ayf=new A.U("U\xe7u\u015f Plan\u0131 & Strip Okuma H\u0131z\u0131","ATC strip'leri ve u\xe7u\u015f plan\u0131 formatlar\u0131 h\u0131zla i\u015flenmesi gereken yo\u011fun bilgi i\xe7erir. ICAO u\xe7u\u015f plan\u0131 formatlar\u0131nda okuma h\u0131z\u0131 antrenman\u0131 yap.")
B.axE=new A.U("Emniyet Prosed\xfcr\xfc El Kitaplar\u0131","\u0130ngilizce \u015firket operasyon el kitaplar\u0131 ve ICAO emniyet belgelerini anlamak, t\xfcm kabin ekibi rolleri i\xe7in zorunludur. Prosed\xfcrel dil kal\u0131plar\u0131na odaklan.")
B.axv=new A.U("Havac\u0131l\u0131k Metni Anlama","ICAO \u0130ngilizce s\u0131navlar\u0131 yo\u011fun operasyonel metinler i\xe7erir. NOTAM, METAR ve AIP al\u0131nt\u0131lar\u0131n\u0131 okuyarak pratik yap \u2014 anahtar bilgiyi h\u0131zl\u0131 tespit etmeye odaklan.")
B.amA=new A.bm(B.qm,[B.az9,B.ayf,B.axE,B.axv],t.dM)
B.qn={pilot:0,atc:1,student:2,cabin_crew:3}
B.ayn=new A.U("Operasyonel Anlam Yorumlama","ATC talimatlar\u0131n\u0131n amac\u0131n\u0131 do\u011fru yorumlamak ve kavramlar\u0131 \u0130ngilizce ile \xe7al\u0131\u015fma dilin aras\u0131nda \xe7evirmek, tehlikeli yanl\u0131\u015f anla\u015f\u0131lmalar\u0131 \xf6nler.")
B.ayp=new A.U("Takas Teyidi & M\xfcsaade Kesinli\u011fi","Clearance readback'teki \xe7eviri hatalar\u0131, pist ihlallerinin \xf6nde gelen nedenidir. Kritik de\u011ferleri yorumlamadan her iki y\xf6nde de kesinlik prati\u011fi yap.")
B.ayV=new A.U("Ba\u011flama Dayal\u0131 Dil Aktar\u0131m\u0131","Kelimesi kelimesine \xe7eviri yerine havac\u0131l\u0131k metinlerini ba\u011flamda anlamaya odaklan. ICAO dili kal\u0131p tabanl\u0131d\u0131r \u2014 kal\u0131plar\u0131 \xf6\u011fren.")
B.aye=new A.U("Emniyet \u0130leti\u015fiminde Do\u011fruluk","Emniyet talimatlar\u0131n\u0131 do\u011fru \xe7evirmek yolcu uyumunu sa\u011flar. Serbest \xe7eviri yerine resmi ICAO emniyet terminolojisine odaklan.")
B.an3=new A.bm(B.qn,[B.ayn,B.ayp,B.ayV,B.aye],t.dM)
B.axN=new A.U("Havac\u0131l\u0131k Kollokasyonlar\u0131 & Sabit \u0130fadeler",'ATC ileti\u015fimlerinin \xe7o\u011fu sabit kollokasyon kullan\u0131r (\xf6r. "cleared for", "report passing"). Bu kal\u0131plar\u0131n tan\u0131nmas\u0131 bo\u015fluk doldurma sorular\u0131nda do\u011frudan s\u0131nan\u0131r.')
B.axR=new A.U("Standart Fraseoloji Kal\u0131plar\u0131","Bo\u015fluk doldurma sorular\u0131 ICAO Doc 4444 standart ifadelerini s\u0131nar. Yayg\u0131n m\xfcsaade ve talimatlar\u0131n tam s\xf6ylemini ezberle.")
B.axH=new A.U("Havac\u0131l\u0131k Kollokasyon Kal\u0131plar\u0131","Havac\u0131l\u0131k \u0130ngilizcesi, genel \u0130ngilizce kurallar\u0131na uymayan belirli s\xf6zc\xfck birle\u015fimleri kullan\u0131r. ICAO e\u011fitim materyallerinden kollokasyonlar\u0131 sistematik bi\xe7imde \xe7al\u0131\u015f.")
B.ayX=new A.U("Emniyet Anonsu \u015eablonlar\u0131","Standart emniyet anonslar\u0131 sabit \u015fablonlar izler. Her anons t\xfcr\xfcn\xfcn tam ifadesini \xf6\u011fren \u2014 bunlar bo\u015fluk doldurma s\u0131navlar\u0131nda s\u0131k\xe7a \xe7\u0131kar.")
B.an5=new A.bm(B.qn,[B.axN,B.axR,B.axH,B.ayX],t.dM)
B.ayQ=new A.U("ATC \u0130leti\u015fiminde S\xf6ylem Ak\u0131\u015f\u0131","ATC/pilot al\u0131\u015fveri\u015flerinin nas\u0131l yap\u0131land\u0131r\u0131ld\u0131\u011f\u0131n\u0131 anlamak, c\xfcmlelerin nas\u0131l tamamland\u0131\u011f\u0131n\u0131 tahmin etmeye yard\u0131mc\u0131 olur. Standart ileti\u015fim dizilerinin mant\u0131ksal ak\u0131\u015f\u0131n\u0131 \xe7al\u0131\u015f.")
B.ay1=new A.U("M\xfcsaadelerde Mant\u0131ksal S\u0131ra","M\xfcsaade c\xfcmleleri \xf6ng\xf6r\xfclebilir mant\u0131ksal kal\u0131plar izler. Bu soru t\xfcr\xfcnde h\u0131z ve do\u011fruluk kazanmak i\xe7in k\u0131smi m\xfcsaadeleri tamamlama prati\u011fi yap.")
B.axw=new A.U("Havac\u0131l\u0131k C\xfcmle Yap\u0131s\u0131","Havac\u0131l\u0131k \u0130ngilizcesi c\xfcmleleri belirli yap\u0131sal kal\u0131plar izler. ICAO ileti\u015fimlerinde bilginin nas\u0131l s\u0131raland\u0131\u011f\u0131n\u0131 \u2014 \xf6nce ne, sonra ne \u2014 \xe7al\u0131\u015f.")
B.ayE=new A.U("Prosed\xfcrel Dil Tamamlama","Emniyet ve hizmet prosed\xfcr\xfc c\xfcmleleri \xf6ng\xf6r\xfclebilir yap\u0131lar izler. Kal\u0131plar\u0131 i\xe7selle\u015ftirmek i\xe7in resmi kabin ekibi ileti\u015fim senaryolar\u0131yla pratik yap.")
B.an4=new A.bm(B.qn,[B.ayQ,B.ay1,B.axw,B.ayE],t.dM)
